 {"id":"asupersync-z454","title":"Implement streaming replay for large traces","description":"## Overview

Implement streaming replay that can process traces incrementally without loading the entire trace into memory, enabling replay of very large traces.

## Problem Statement

Large traces (millions of events) cannot fit in memory. We need streaming support:
1. Streaming write: Write events as they occur, don't buffer all in memory
2. Streaming read: Read and process events one at a time during replay
3. Memory-bounded: Constant memory usage regardless of trace size

## Design

### Streaming TraceWriter

```rust
pub struct StreamingTraceWriter {
    file: BufWriter<File>,
    events_written: u64,
    checksum: Hasher,
}

impl StreamingTraceWriter {
    pub fn create(path: impl AsRef<Path>) -> io::Result<Self> {
        let file = File::create(path)?;
        let mut writer = BufWriter::with_capacity(64 * 1024, file);

        // Write header placeholder (will update on finish)
        write_header_placeholder(&mut writer)?;

        Ok(Self {
            file: writer,
            events_written: 0,
            checksum: Hasher::new(),
        })
    }

    /// Write a single event. Does NOT buffer - writes immediately.
    pub fn write_event(&mut self, event: &TraceEvent) -> io::Result<()> {
        let bytes = bincode::serialize(event)
            .map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))?;

        // Write length-prefixed
        self.file.write_all(&(bytes.len() as u32).to_le_bytes())?;
        self.file.write_all(&bytes)?;

        self.checksum.update(&bytes);
        self.events_written += 1;

        // Flush periodically for durability
        if self.events_written % 10_000 == 0 {
            self.file.flush()?;
        }

        Ok(())
    }

    /// Finish writing, update header with event count and checksum.
    pub fn finish(mut self) -> io::Result<TraceFileStats> {
        self.file.flush()?;

        // Seek back and update header
        let file = self.file.into_inner()?;
        // ... update header with events_written and checksum

        Ok(TraceFileStats {
            events: self.events_written,
            checksum: self.checksum.finalize(),
        })
    }
}
```

### Streaming TraceReader

```rust
pub struct StreamingTraceReader {
    file: BufReader<File>,
    metadata: TraceMetadata,
    events_read: u64,
    total_events: u64,
}

impl StreamingTraceReader {
    pub fn open(path: impl AsRef<Path>) -> io::Result<Self> {
        let file = File::open(path)?;
        let mut reader = BufReader::with_capacity(64 * 1024, file);

        let header = read_header(&mut reader)?;
        let metadata = read_metadata(&mut reader)?;

        Ok(Self {
            file: reader,
            metadata,
            events_read: 0,
            total_events: header.event_count,
        })
    }

    /// Read next event. Returns None at end of trace.
    pub fn next_event(&mut self) -> io::Result<Option<TraceEvent>> {
        if self.events_read >= self.total_events {
            return Ok(None);
        }

        // Read length prefix
        let mut len_bytes = [0u8; 4];
        self.file.read_exact(&mut len_bytes)?;
        let len = u32::from_le_bytes(len_bytes) as usize;

        // Read event bytes
        let mut bytes = vec![0u8; len];
        self.file.read_exact(&mut bytes)?;

        let event = bincode::deserialize(&bytes)
            .map_err(|e| io::Error::new(io::ErrorKind::InvalidData, e))?;

        self.events_read += 1;
        Ok(Some(event))
    }

    /// Progress through trace (0.0 to 1.0).
    pub fn progress(&self) -> f64 {
        self.events_read as f64 / self.total_events as f64
    }
}

impl Iterator for StreamingTraceReader {
    type Item = io::Result<TraceEvent>;

    fn next(&mut self) -> Option<Self::Item> {
        match self.next_event() {
            Ok(Some(event)) => Some(Ok(event)),
            Ok(None) => None,
            Err(e) => Some(Err(e)),
        }
    }
}
```

### Streaming Replayer

```rust
pub struct StreamingReplayer {
    reader: StreamingTraceReader,
    current_event: Option<TraceEvent>,
    runtime: LabRuntime,
}

impl StreamingReplayer {
    /// Create replayer that streams from file.
    pub fn open(path: impl AsRef<Path>) -> io::Result<Self> {
        let reader = StreamingTraceReader::open(path)?;
        let runtime = LabRuntime::new_replay_mode(reader.metadata().clone());

        Ok(Self {
            reader,
            current_event: None,
            runtime,
        })
    }

    /// Peek at next event without consuming.
    pub fn peek(&mut self) -> io::Result<Option<&TraceEvent>> {
        if self.current_event.is_none() {
            self.current_event = self.reader.next_event()?;
        }
        Ok(self.current_event.as_ref())
    }

    /// Consume next event and apply to runtime.
    pub fn step(&mut self) -> io::Result<Option<ReplayStep>> {
        let event = match self.peek()? {
            Some(_) => self.current_event.take().unwrap(),
            None => return Ok(None),
        };

        let step = self.runtime.apply_replay_event(&event)?;
        Ok(Some(step))
    }

    /// Run to completion, streaming events.
    pub fn run_to_end(&mut self) -> io::Result<ReplayResult> {
        while self.step()?.is_some() {
            // Continue
        }
        Ok(self.runtime.finish_replay())
    }
}
```

## Memory Constraints

- StreamingTraceWriter: O(1) memory (just buffer)
- StreamingTraceReader: O(1) memory (just buffer + current event)
- StreamingReplayer: O(runtime state) - not O(trace size)

## Checkpointing (Optional Enhancement)

For very long replays, support checkpointing:

```rust
impl StreamingReplayer {
    /// Save replay state for later resumption.
    pub fn checkpoint(&self) -> io::Result<ReplayCheckpoint> {
        Ok(ReplayCheckpoint {
            event_index: self.reader.events_read,
            runtime_state: self.runtime.snapshot(),
        })
    }

    /// Resume from checkpoint.
    pub fn resume(path: impl AsRef<Path>, checkpoint: ReplayCheckpoint) -> io::Result<Self> {
        let mut reader = StreamingTraceReader::open(path)?;

        // Skip to checkpoint position
        for _ in 0..checkpoint.event_index {
            reader.next_event()?;
        }

        let runtime = LabRuntime::from_snapshot(checkpoint.runtime_state);

        Ok(Self {
            reader,
            current_event: None,
            runtime,
        })
    }
}
```

## Tests

```rust
#[test]
fn streaming_handles_large_traces() {
    let temp = tempfile::NamedTempFile::new().unwrap();

    // Write 10M events (would be ~500MB in memory)
    {
        let mut writer = StreamingTraceWriter::create(temp.path()).unwrap();
        for i in 0..10_000_000 {
            writer.write_event(&TraceEvent::TaskScheduled {
                task_id: TaskId(i),
                at_tick: i,
            }).unwrap();
        }
        writer.finish().unwrap();
    }

    // Read streaming - memory should stay bounded
    {
        let reader = StreamingTraceReader::open(temp.path()).unwrap();
        let mut count = 0;
        for event in reader {
            let _ = event.unwrap();
            count += 1;
        }
        assert_eq!(count, 10_000_000);
    }
}

#[test]
fn streaming_replay_constant_memory() {
    // Use memory profiling to verify O(1) memory usage
    let baseline_memory = get_current_memory();

    let temp = tempfile::NamedTempFile::new().unwrap();
    // ... create large trace ...

    let mut replayer = StreamingReplayer::open(temp.path()).unwrap();
    replayer.run_to_end().unwrap();

    let peak_memory = get_peak_memory();
    let memory_growth = peak_memory - baseline_memory;

    // Should not grow by more than a few MB regardless of trace size
    assert!(memory_growth < 10_000_000, "Memory grew by {} bytes", memory_growth);
}
```

## Acceptance Criteria

- [ ] StreamingTraceWriter with O(1) memory
- [ ] StreamingTraceReader with O(1) memory
- [ ] StreamingReplayer that doesn't load full trace
- [ ] 10M event trace can be written and read
- [ ] Memory usage is bounded regardless of trace size
- [ ] Progress reporting during streaming
- [ ] Optional checkpointing for long replays","status":"closed","priority":2,"issue_type":"task","owner":"jeff141421@gmail.com","created_at":"2026-01-18T19:09:13.509749549Z","created_by":"Dicklesworthstone","updated_at":"2026-01-21T09:56:17.074923451Z","closed_at":"2026-01-21T09:56:17.074793396Z","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"asupersync-z454","depends_on_id":"asupersync-cdmp","type":"blocks","created_at":"2026-01-27T06:20:45Z","created_by":"import"}]}
-{"id":"asupersync-z8n","title":"[fastapi-integration] 1.3: Connection Lifecycle and Graceful Shutdown","description":"# 1.3: Connection Lifecycle and Graceful Shutdown

## Objective
Design connection lifecycle management and graceful shutdown for HTTP servers built on Asupersync.

## Background

### Why Graceful Shutdown Matters
For zero-downtime deployments, an HTTP server must:
1. Stop accepting new connections
2. Wait for in-flight requests to complete (with timeout)
3. Forcefully terminate remaining connections
4. Release all resources

Asupersync's structured concurrency makes this pattern first-class.

### Current Asupersync Capabilities
- **Regions**: Connection and request lifecycle maps to region tree
- **Cancellation Protocol**: Request → Drain → Finalize with budgets
- **Finalizers**: Cleanup runs even on cancellation

## Requirements

### 1. Connection Lifecycle as Regions
```
Server Region (lifetime: until shutdown)
│
├── Acceptor Region (lifetime: until stop accepting)
│   └── Task: accept loop
│
└── Connections Region (lifetime: drain period + force timeout)
    │
    ├── Connection[1] Region (lifetime: connection)
    │   ├── Request[1.1] Region (lifetime: single request)
    │   ├── Request[1.2] Region
    │   └── ...
    │
    └── Connection[2] Region
        └── ...
```

### 2. Shutdown Phases
```rust
pub enum ShutdownPhase {
    /// Normal operation
    Running,
    /// Stopped accepting, draining in-flight
    Draining { until: Instant },
    /// Force-closing remaining connections
    ForceClosing,
    /// All connections closed
    Stopped,
}

impl Server {
    /// Initiate graceful shutdown.
    ///
    /// 1. Stop accepting new connections
    /// 2. Cancel acceptor region
    /// 3. Wait for connections to drain (respecting request budgets)
    /// 4. If drain timeout exceeded, force-cancel remaining
    /// 5. Return when all connections closed
    pub async fn shutdown(
        &self, 
        cx: &Cx<'_>, 
        drain_timeout: Duration,
    ) -> Outcome<ShutdownStats, ShutdownError> {
        // Implementation uses region cancellation
    }
}
```

### 3. Connection Manager
```rust
/// Tracks all active connections for shutdown coordination.
pub struct ConnectionManager {
    connections: ConnectionRegistry,
    max_connections: Option<usize>,
    shutdown_signal: ShutdownSignal,
}

impl ConnectionManager {
    /// Register a new connection. Returns None if at max capacity.
    pub fn register(&self, addr: SocketAddr) -> Option<ConnectionGuard>;

    /// Initiate shutdown: returns future that completes when drained.
    pub fn shutdown(&self) -> ShutdownFuture;

    /// Get current connection count.
    pub fn active_count(&self) -> usize;

    /// Get shutdown state.
    pub fn state(&self) -> ShutdownPhase;
}
```

### 4. Connection Guard Pattern
```rust
/// RAII guard that deregisters connection on drop.
pub struct ConnectionGuard {
    manager: Arc<ConnectionManager>,
    id: ConnectionId,
}

impl Drop for ConnectionGuard {
    fn drop(&mut self) {
        self.manager.deregister(self.id);
    }
}

// Usage in accept loop:
loop {
    let (stream, addr) = listener.accept(cx).await?;
    let Some(guard) = manager.register(addr) else {
        // At capacity, reject connection
        continue;
    };
    cx.spawn(async move {
        let _guard = guard;  // Kept alive for connection lifetime
        handle_connection(stream).await;
    });
}
```

### 5. Request Draining
```rust
/// Per-request handling with shutdown awareness.
async fn handle_request(
    cx: &Cx<'_>,
    request: Request,
    shutdown: &ShutdownSignal,
) -> Outcome<Response, RequestError> {
    // Check if shutting down
