    /// Initiate graceful shutdown.
    ///
    /// 1. Stop accepting new connections
    /// 2. Cancel acceptor region
    /// 3. Wait for connections to drain (respecting request budgets)
    /// 4. If drain timeout exceeded, force-cancel remaining
    /// 5. Return when all connections closed
    pub async fn shutdown(
        &self, 
        cx: &Cx<'_>, 
        drain_timeout: Duration,
    ) -> Outcome<ShutdownStats, ShutdownError> {
        // Implementation uses region cancellation
    }
}
```

